import SwiftUI
import UIKit

private enum EmbeddedImages {
    static let aptumLogo = ""
    static let aptumBike = ""

    static func uiImage(_ base64: String) -> UIImage? {
        guard let data = Data(base64Encoded: base64) else { return nil }
        return UIImage(data: data)
    }
}

struct AptumLogoImage: View {
    var body: some View {
        if let image = EmbeddedImages.uiImage(EmbeddedImages.aptumLogo) {
            Image(uiImage: image)
                .resizable()
                .scaledToFit()
        } else {
            Image("AptumLogo")
                .resizable()
                .scaledToFit()
        }
    }
}

struct AptumBikeImage: View {
    var body: some View {
        if let image = EmbeddedImages.uiImage(EmbeddedImages.aptumBike) {
            Image(uiImage: image)
                .resizable()
                .scaledToFit()
        } else {
            Image(systemName: "bicycle")
                .font(.largeTitle)
                .foregroundStyle(.cyan)
        }
    }
}
